                    "clearingMethod": "PAY-AS-CLEAR",
                    "clearingTime": "2026-06-15T12:00:00Z",
                    "currency": "INR",
                    "baselineMethodology": {
                      "bestOf": 5,
                      "outOf": 10
                    },
                    "penaltyRate": 0.5
                  }
                },
                {
                  "role": "seller",
                  "participantId": "greenflex-agg",
                  "inputs": {
                    "participatingMeters": ["der://meter/001", "der://meter/002"],
