            "@context": "https://schema.beckn.io/BecknTimeSeries/v1.0/context.jsonld",
            "@type": "TimeSeries",
            "intervalPeriod": {
              "start": "2026-06-15T13:30:00Z",
              "duration": "PT1H"
            },
            "payloadDescriptors": [
              {"objectType": "EVENT_PAYLOAD_DESCRIPTOR", "payloadType": "BID_PRICE", "units": "INR_PER_KWH", "insertedBy": "seller"},
              {"objectType": "EVENT_PAYLOAD_DESCRIPTOR", "payloadType": "BID_POWER", "units": "KW", "insertedBy": "seller"}
            ],
            "intervals": [
              {"id": 0, "payloads": [{"type": "BID_PRICE", "values": [1.5, 2.5, 3.5, 5.0]}, {"type": "BID_POWER", "values": [90, 70, 50, 30]}]},
