            ]
          }
        }
      ],
      "contractAttributes": {
        "@context": "https://schema.beckn.io/DEGContract/v2.0/context.jsonld",
        "@type": "DEGContract",
        "roles": [
          {"role": "buyer", "participantId": "tpddl-north-delhi"},
          {"role": "seller", "participantId": "greenflex-agg"}
        ],
        "policy": {
          "url": "https://raw.githubusercontent.com/beckn/DEG/refs/heads/main/specification/policies/demand_flex_pac_revenue.rego",
          "queryPath": "data.deg.contracts.demand_flex_pac"
        }
      },
      "participants": [
        {"role": "buyer", "participantId": "tpddl-north-delhi"},
        {"role": "seller", "participantId": "greenflex-agg"}
      ],
      "consideration": [
        {
          "id": "payment-term-pac-001",
          "considerationAttributes": {
            "@context": "https://schema.beckn.io/SettlementTerm/2.0/context.jsonld",
            "@type": "SettlementTerm",
            "settlementStatus": "PENDING",
            "paymentTrigger": "ON_FULFILLMENT",
            "payTo": {
              "accountHolderName": "GreenFlex Aggregator Pvt Ltd",
              "accountNumber": "4567890123456",
              "branchCode": "ICIC0002345",
              "bankName": "ICICI Bank"
            },
            "acceptedPaymentMethods": ["BANK_TRANSFER"]
          }
        }
      ]
    }
  }
}

